import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  Button,
  TextInput,
  StyleSheet,
  Alert,
  ActivityIndicator,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import RnBiometrics from 'react-native-biometrics';

const AUTH_KEY = 'authenticated';
const CORRECT_PASSWORD = 'password123'; // IMPORTANT: Replace with a secure authentication method (e.g., backend API call)

const BiometricLoginScreen = ({ onLoginSuccess }) => {
  const [loading, setLoading] = useState(true);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null); // e.g., 'Face ID', 'Touch ID', 'Biometrics'
  const [password, setPassword] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    checkAuthenticationStatusAndBiometrics();
  }, []);

  const checkAuthenticationStatusAndBiometrics = async () => {
    try {
      setLoading(true);

      // 1. Check if already authenticated via AsyncStorage
      const storedAuth = await AsyncStorage.getItem(AUTH_KEY);
      if (storedAuth === 'true') {
        setIsAuthenticated(true);
        onLoginSuccess(); // Trigger parent to navigate away from login
        return; // Skip further checks if already authenticated
      }

      // 2. Check biometric availability
      const { available, biometryType } = await RnBiometrics.isSensorAvailable();
      if (available) {
        setBiometricsAvailable(true);
        setBiometricType(biometryType);
        // Automatically prompt biometrics if available and not already authenticated
        handleBiometricAuth();
      } else {
        setBiometricsAvailable(false);
        // Alert.alert('Biometrics Not Available', 'Your device does not support biometrics or it is not enabled. Please use password.');
      }
    } catch (error) {
      console.error('Error checking authentication or biometrics:', error);
      Alert.alert('Error', 'Could not check authentication status. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleBiometricAuth = async () => {
    if (!biometricsAvailable) {
      Alert.alert('Biometrics Not Available', 'Your device does not support biometrics or it is not enabled. Please use password.');
      return;
    }
    try {
      const { success } = await RnBiometrics.simplePrompt({
        promptMessage: `Authenticate with ${biometricType}`,
        cancelButtonText: 'Use Password', // Customize cancel button text for Android
      });

      if (success) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        setIsAuthenticated(true);
        Alert.alert('Success', 'Biometric authentication successful!');
        onLoginSuccess(); // Trigger parent to navigate
      } else {
        // User cancelled or authentication failed
        Alert.alert('Authentication Failed', 'Biometric authentication failed or was cancelled. Please try password.');
      }
    } catch (error) {
      console.error('Biometric authentication error:', error);
      // Specific error handling for react-native-biometrics
      if (error.code === 'USER_CANCELED') {
        Alert.alert('Cancelled', 'Biometric authentication was cancelled.');
      } else if (error.code === 'NOT_ENROLLED') {
        Alert.alert('No Biometrics Enrolled', 'Please set up Face ID or Touch ID in your device settings.');
      } else {
        Alert.alert('Error', 'An error occurred during biometric authentication.');
      }
    }
  };

  const handlePasswordLogin = async () => {
    if (password === CORRECT_PASSWORD) {
      await AsyncStorage.setItem(AUTH_KEY, 'true');
      setIsAuthenticated(true);
      Alert.alert('Success', 'Password login successful!');
      onLoginSuccess();
    } else {
      Alert.alert('Error', 'Incorrect password.');
    }
  };

  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_KEY);
    setIsAuthenticated(false);
    setPassword('');
    Alert.alert('Logged Out', 'You have been logged out.');
    // Re-check biometrics after logout, in case user wants to login with it again
    checkAuthenticationStatusAndBiometrics();
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
        <Text style={styles.text}>Checking authentication...</Text>
      </View>
    );
  }

  if (isAuthenticated) {
    return (
      <View style={styles.container}>
        <Text style={styles.title}>Welcome!</Text>
        <Text style={styles.text}>You are authenticated.</Text>
        <Button title="Logout" onPress={handleLogout} />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricsAvailable && (
        <View style={styles.section}>
          <Text style={styles.text}>
            Authenticate with your {biometricType || 'biometrics'}:
          </Text>
          <Button title={`Use ${biometricType || 'Biometrics'}`} onPress={handleBiometricAuth} />
        </View>
      )}

      {!biometricsAvailable && (
        <Text style={styles.infoText}>
          Biometrics not available or not enabled. Please use password to log in.
        </Text>
      )}

      <View style={styles.section}>
        <Text style={styles.text}>Or login with password:</Text>
        <TextInput
          style={styles.input}
          placeholder="Enter password"
          secureTextEntry
          value={password}
          onChangeText={setPassword}
          autoCapitalize="none"
        />
        <Button title="Login with Password" onPress={handlePasswordLogin} />
      </View>
    </View>
  );
};

